# Unit Tests for `add` Function

```python
import pytest
from math import inf


def add(a: int, b: int) -> int:
    return a + b


# ---------------------------------------------------------------------------
# Happy path
# ---------------------------------------------------------------------------

class TestAddHappyPath:
    def test_two_positive_integers(self):
        assert add(2, 3) == 5

    def test_two_large_positive_integers(self):
        assert add(1_000_000, 2_000_000) == 3_000_000

    def test_positive_and_negative(self):
        assert add(10, -4) == 6

    def test_two_negative_integers(self):
        assert add(-3, -7) == -10

    def test_result_is_int(self):
        result = add(1, 2)
        assert isinstance(result, int)


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------

class TestAddEdgeCases:
    def test_both_zero(self):
        assert add(0, 0) == 0

    def test_zero_and_positive(self):
        assert add(0, 5) == 5

    def test_positive_and_zero(self):
        assert add(5, 0) == 5

    def test_zero_and_negative(self):
        assert add(0, -5) == -5

    def test_additive_inverse(self):
        """Opposites should sum to zero."""
        assert add(42, -42) == 0

    def test_very_large_integers(self):
        """Python handles arbitrarily large integers natively."""
        big = 10 ** 100
        assert add(big, big) == 2 * big

    def test_very_small_negative_integers(self):
        big_neg = -(10 ** 100)
        assert add(big_neg, big_neg) == 2 * big_neg

    def test_commutative_property(self):
        assert add(3, 7) == add(7, 3)

    def test_associative_property(self):
        assert add(add(1, 2), 3) == add(1, add(2, 3))


# ---------------------------------------------------------------------------
# Error / type cases
# ---------------------------------------------------------------------------

class TestAddErrorCases:
    def test_float_arguments_raises(self):
        with pytest.raises(TypeError):
            add(1.5, 2)  # type: ignore[arg-type]

    def test_string_arguments_raises(self):
        with pytest.raises(TypeError):
            add("1", "2")  # type: ignore[arg-type]

    def test_none_argument_raises(self):
        with pytest.raises(TypeError):
            add(None, 1)  # type: ignore[arg-type]

    def test_list_argument_raises(self):
        with pytest.raises(TypeError):
            add([1], [2])  # type: ignore[arg-type]

    def test_infinity_raises(self):
        with pytest.raises(TypeError):
            add(inf, 1)  # type: ignore[arg-type]

    def test_missing_argument_raises(self):
        with pytest.raises(TypeError):
            add(1)  # type: ignore[call-arg]

    def test_too_many_arguments_raises(self):
        with pytest.raises(TypeError):
            add(1, 2, 3)  # type: ignore[call-arg]


# ---------------------------------------------------------------------------
# Parametrized tests (concise coverage of multiple cases)
# ---------------------------------------------------------------------------

@pytest.mark.parametrize("a, b, expected", [
    (0,   0,   0),
    (1,   1,   2),
    (-1, -1,  -2),
    (100, -50, 50),
    (-10,  10,  0),
    (999, 1,  1000),
])
def test_add_parametrized(a, b, expected):
    assert add(a, b) == expected
